INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (3, 1, 1, 'Vợt cầu lông Yonex Astrox 100 Tour VA', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Vợt cầu lông Yonex Astrox 100 Tour VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/vot-cau-long-yonex-astrox-100-tour-va.html">Vợt cầu lông Yonex Astrox 100 Tour VA</a> là một trong những siêu phẩm mới nhất mà Yonex vừa giới thiệu, kế thừa trọn vẹn tinh hoa công nghệ của dòng Astrox – biểu tượng của lối chơi tấn công mạnh mẽ với những cú đập cầu uy lực và góc đánh hiểm hóc. Đây là phiên bản giới hạn với bộ nhận diện riêng về màu sắc và thương hiệu, được áp dụng cho toàn bộ dòng Astrox 100 VA. So với bản gốc, Astrox 100 Tour VA vẫn giữ trọn tinh thần của nhà vô địch nhưng ở mức giá dễ tiếp cận hơn, phù hợp cho người chơi muốn trải nghiệm hiệu suất thi đấu ở đẳng cấp cao.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="b5Tp5UP2KNk" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/b5Tp5UP2KNk/maxresdefault.jpg);"></div></div></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Khả năng tấn công chính là điểm nổi bật nhất của 100VA Tour. Cây vợt có điểm cân bằng nặng đầu, hỗ trợ tạo ra những cú smash mạnh và nhanh. Thân vợt cứng cho phép tích lũy năng lượng tốt, từ đó giải phóng lực đánh với quỹ đạo cầu cắm và sức nặng cao. Tuy nhiên, thiết kế này đòi hỏi người chơi phải có lực cổ tay đủ khỏe để khai thác tối đa hiệu quả. Nhằm nâng cao hiệu suất tối ưu của người chơi trên sân đấu, Astrox 100 Tour VA thừa hưởng gần như toàn bộ các công nghệ cốt lõi từ phiên bản cao cấp nhưng được tinh chỉnh để trở nên dễ tiếp cận hơn, với độ cứng thấp hơn một chút và mức giá phải chăng hơn.</span></span></p>
<p style="text-align: center;"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="-2TKk4q7gGw" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/-2TKk4q7gGw/maxresdefault.jpg);"></div></div></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số Vợt cầu lông Yonex Astrox 100 Tour VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cứng: Cứng</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Điểm cân bằng: Nặng đầu</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Khung mặt vợt: HM Graphite, NANOMESH NEO, VOLUME CUT RESIN, Tungsten</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đũa vợt: HM Graphite, Namd</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Joint: Built-in T-Joint</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng: 3U, 4U</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chu vi cán vợt: 3U - G4, 5, 6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">                           4U - G5, 6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Màu sắc: Dark Olive</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Sức căng vợt: 4U: 20 - 28 lbs</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">                          3U: 21 - 29 lbs</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ tích hợp trên Vợt cầu lông Yonex Astrox 100 Tour VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- NAMD:</strong> Là công nghệ phủ vật liệu nano lên trực tiếp vào sợi than chì cải thiện sự kết dính giữa than chì và nhựa giúp tăng độ đàn hồi cho phần đũa của vợt cầu lông Yonex Astrox 100 Tour VA và giúp đũa vợt quay lại trạng thái ổn định nhất.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Công nghệ NANOMESH NEO </strong>của Yonex sử dụng chất kết dính giúp kết hợp sợi Graphite với nhựa cho khung vợt chắc chắn và linh hoạt hơn, trong khi độ uốn thân vợt tăng lên tạo ra sức mạnh tối đa.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- AERO-BOX FRAME:</strong> Mục đích của việc thiết kế mặt khung hình oval là để khi đánh vợt sẽ lướt gió cho không khí qua, BOX FRAME vát 2 bên giúp vợt cứng cáp hơn. Thiết kế giúp tăng khí động lực học, giúp chúng ta vung vợt nhanh hơn, đập cầu mạnh hơn</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ISOMETRIC: </strong>Công nghệ thiết kế hình vuông giúp đảm bảo tính tương đồng về độ dài và góc của các dây dọc cũng như dây ngang, tăng tối đa điểm ngọt theo mọi hướng, phần khung của vợt Yonex Astrox 100 Tour VA vuông hơn nên khi cầu chạm mặt vợt ở những điểm khác nhau trên mặt vợt vẫn mang lại cảm giác đánh tốt nhất.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ROTATIONAL GENARATOR SYSTEM: </strong>Là công nghệ theo thuyết đối trọng. Trọng lực được phân bổ ở đầu, đoạn nối chữ T và phần đầu vợt Yonex Astrox 100. Việc phân bổ như vậy giúp cho cây vợt được đồng đều, hỗ trợ tốt nhất cho vợt sau khi đánh xong quả cầu trước và chuẩn bị cho pha đánh cầu tiếp theo dễ dàng hơn. Điều này giúp cho việc dù đang cầm vợt nặng đầu nhưng vẫn mang đến cảm giác cân bằng, thoải mái.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- SOLID FEEL CORE: </strong>Công nghệ được áp dụng bên trong lõi của khung cây vợt cầu lông. Bên trong lõi có lớp xốp. Lớp xốp này có vai trò cắt giảm  những rung động có hại, mục địch chính là  giúp hấp thụ chấn, chống sốc lên tay khi tay phải chịu áp lực từ thân vợt cứng. SOLIC FEEL CORE được áp dụng trong tất cả các cây vợt được sản xuất tại Nhật Bản.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- EXTRA SLIM SHAFTS</strong> là công nghệ được thiết kế bởi nhà Yonex tạo nên đũa vợt mỏng để cắt khí và tạo ra sức mạnh nhanh chóng cho mỗi cú đập và sự linh hoạt trong những pha phản tạt, phòng thủ với nhịp độ nhanh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Energy Boost CAP PLUS:</strong> Chụp mũ vợt trên Yonex Astrox 100 Tour VA có hình dạng độc đáo giúp tối đa hóa hiệu suất của trục. Mặt trước cho phép trục uốn cong, trong khi đường cong hình vòm hai bên giúp ổn định mặt vợt bằng cách ngăn trục xoắn. Ngoài ra, với thiết kế này cũng sẽ giúp cây vợt có điểm tựa lớn hơn trong các pha cầu tì đè, bắt lưới cần cầm cao cán vợt.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- REXIS SHAFT</strong> là công nghệ được phát minh bởi hãng Yonex tạo ra một loại thân vợt hiệu suất cao được thiết kế chính xác và tỉ mĩ với kỹ thuật đúng mẫu hình Yonex nguyên bản. Cải thiện hiệu suất đánh cầu và làm chủ trận đấu.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- NEW BIULT-IN T-JOINT:</strong> Được sản xuất từ một loại nhựa nhẹ đặc biệt kết hợp với nhựa Epoxy và chất tạo bọt giúp tăng cường chất lượng và hiệu suất bằng cách tăng độ ổn định của quả cầu trên mặt vợt. Công nghệ được áp dụng ở phần chữ T của vợt giúp hỗ trợ vợt tránh xoắn vợt sau khi thực hiện cú đánh trước đó giúp vợt nhanh chóng lấy lại ổn định cho những cú đánh tiếp theo và giúp tăng kiểm soát cầu.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>4. Đối tượng phù hợp với Vợt cầu lông Yonex Astrox 100 Tour VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Vợt cầu lông Yonex Astrox 100 Tour VA dành cho những người mong muốn sở hữu một cây vợt cầu lông tấn công hàng đầu mà không quá khó chơi cùng mức giá hợp lý, Astrox 100VA Tour sẽ là một trong những lựa chọn đáng đầu tư nhất trên thị trường hiện nay.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Với phiên bản 4U mang lại sự cân bằng tốt hơn giữa sức mạnh và khả năng xoay sở, được khuyến nghị trong đánh đôi., còn phiên bản 3U thì dành cho những người chơi có cổ tay khỏe và đòi hỏi thể lực cao, những người muốn tối đa hóa sức mạnh đập cầu.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'vot-cau-long-yonex-astrox-100-tour-va', TRUE, NOW(), NOW());
