INSERT INTO product_specifications (id, product_id, name, value) VALUES (1, 3, 'NAMD', 'Là công nghệ phủ vật liệu nano lên trực tiếp vào sợi than chì cải thiện sự kết dính giữa than chì và nhựa giúp tăng độ đàn hồi cho phần đũa của vợt cầu lông Yonex Astrox 100 Tour VA và giúp đũa vợt quay lại trạng thái ổn định nhất');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (2, 3, 'AERO-BOX FRAME', 'Mục đích của việc thiết kế mặt khung hình oval là để khi đánh vợt sẽ lướt gió cho không khí qua, BOX FRAME vát 2 bên giúp vợt cứng cáp hơn. Thiết kế giúp tăng khí động lực học, giúp chúng ta vung vợt nhanh hơn, đập cầu mạnh hơn');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (3, 3, 'ISOMETRIC', 'Công nghệ thiết kế hình vuông giúp đảm bảo tính tương đồng về độ dài và góc của các dây dọc cũng như dây ngang, tăng tối đa điểm ngọt theo mọi hướng, phần khung của vợt Yonex Astrox 100 Tour VA vuông hơn nên khi cầu chạm mặt vợt ở những điểm khác nhau trê');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (4, 3, 'ROTATIONAL GENARATOR SYSTEM', 'Là công nghệ theo thuyết đối trọng. Trọng lực được phân bổ ở đầu, đoạn nối chữ T và phần đầu vợt Yonex Astrox 100. Việc phân bổ như vậy giúp cho cây vợt được đồng đều, hỗ trợ tốt nhất cho vợt sau khi đánh xong quả cầu trước và chuẩn bị cho pha đánh cầu ti');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (5, 3, 'SOLID FEEL CORE', 'Công nghệ được áp dụng bên trong lõi của khung cây vợt cầu lông. Bên trong lõi có lớp xốp. Lớp xốp này có vai trò cắt giảm những rung động có hại, mục địch chính là giúp hấp thụ chấn, chống sốc lên tay khi tay phải chịu áp lực từ thân vợt cứng. SOLIC FEEL');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (6, 3, 'Energy Boost CAP PLUS', 'Chụp mũ vợt trên Yonex Astrox 100 Tour VA có hình dạng độc đáo giúp tối đa hóa hiệu suất của trục. Mặt trước cho phép trục uốn cong, trong khi đường cong hình vòm hai bên giúp ổn định mặt vợt bằng cách ngăn trục xoắn. Ngoài ra, với thiết kế này cũng sẽ gi');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (7, 3, 'NEW BIULT-IN T-JOINT', 'Được sản xuất từ một loại nhựa nhẹ đặc biệt kết hợp với nhựa Epoxy và chất tạo bọt giúp tăng cường chất lượng và hiệu suất bằng cách tăng độ ổn định của quả cầu trên mặt vợt. Công nghệ được áp dụng ở phần chữ T của vợt giúp hỗ trợ vợt tránh xoắn vợt sau k');
