INSERT INTO product_specifications (id, product_id, name, value) VALUES (12, 8, 'NANOMESH NEO', 'Chất liệu carbon kết hợp nhựa giúp khung vợt bền và dẻo hơn, tăng khả năng uốn và phục hồi nhanh, hỗ trợ truyền lực tốt cho những pha cầu liên tục');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (13, 8, 'ISOMETRIC', 'Thiết kế khung vuông giúp mở rộng điểm ngọt, tăng độ chính xác và ổn định ngay cả khi đánh lệch tâm');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (14, 8, 'AERO-BOX FRAME', 'Khung kết hợp giữa độ cứng và khí động học, giảm lực cản không khí, giúp vung vợt nhanh và linh hoạt hơn');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (15, 8, 'BUILT-IN T-JOINT', 'Gia cố khớp chữ T bằng vật liệu cứng, tăng độ ổn định, hạn chế xoắn vợt và cải thiện cảm giác cầu');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (16, 8, 'CONTROL SUPPORT CAP', 'Thiết kế mũ vợt tối ưu điểm tựa tay cầm, giúp cầm chắc chắn hơn và nâng cao khả năng kiểm soát trong từng cú đánh');
