INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (9, 1, 1, 'Vợt cầu lông Yonex Astrox 100 Game VA', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Vợt cầu lông Yonex Astrox 100 Game VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/vot-cau-long-yonex-astrox-100-game-va.html">Vợt cầu lông Yonex Astrox 100 Game VA</a> Lấy cảm hứng từ phiên bản cao cấp Astrox 100ZZ VA, cây vợt này được tinh chỉnh khéo léo mang đến sức mạnh tấn công vượt trội, dễ làm quen và đặc biệt có mức giá hợp lý hơn, phù hợp cho người chơi trình độ thấp hơn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Astrox 100 Game VA sử dụng một tổ hợp vật liệu tiên tiến được lựa chọn để nâng cao hiệu suất. Trong đó, HM Graphite cung cấp độ cứng cáp và bền bỉ cho khung vợt, đảm bảo vợt không bị biến dạng dưới lực căng cao và những cú va chạm mạnh. Các hạt Tungsten được tích hợp vào khung giúp tăng cường sức mạnh cho các cú đập và cải thiện độ ổn định của mặt vợt khi tiếp xúc cầu.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="b5Tp5UP2KNk" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/b5Tp5UP2KNk/maxresdefault.jpg);"></div></div></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thuộc phân khúc giá tầm trung, Astrox 100 Game VA được thừa hưởng những công nghệ tinh túy nhất từ dòng cao cấp hơn, tạo nên sự khác biệt rõ rệt khi đánh. Trong đó, Rotational Generator System được  phân bố trọng lượng tập trung ở đầu vợt, khớp nối và cán vợt. Từ đó, cung cấp những cú đẩy cầu với sức mạnh bùng nổ, đồng thời linh hoạt giữa các pha chuyển tiếp giữa các pha cầu.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số Vợt cầu lông Yonex Astrox 100 Game VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cứng: Trung bình</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Điểm cân bằng: Nặng đầu</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Khung mặt vợt: HM Graphite, NANOMESH NEO, VOLUME CUT RESIN, Tungsten</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đũa vợt: HM Graphite, NANOMESH NEO</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Joint: Built-in T-Joint</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng: 3U, 4U</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chu vi cán vợt: 3U - G4, 5, 6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">                           4U - G5, 6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Màu sắc: Grayish Beige</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Sức căng vợt: 4U: 20 - 28 lbs</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">                          3U: 21 - 29 lbs</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ tích hợp trên Vợt cầu lông Yonex Astrox 100 Game VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Công nghệ NANOMESH NEO </strong>của Yonex sử dụng chất kết dính giúp kết hợp sợi Graphite với nhựa cho khung vợt chắc chắn và linh hoạt hơn, trong khi độ uốn thân vợt tăng lên tạo ra sức mạnh tối đa.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- AERO-BOX FRAME:</strong> Mục đích của việc thiết kế mặt khung hình oval là để khi đánh vợt sẽ lướt gió cho không khí qua, BOX FRAME vát 2 bên giúp vợt cứng cáp hơn. Thiết kế giúp tăng khí động lực học, giúp chúng ta vung vợt nhanh hơn, đập cầu mạnh hơn</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ISOMETRIC: </strong>Công nghệ thiết kế hình vuông giúp đảm bảo tính tương đồng về độ dài và góc của các dây dọc cũng như dây ngang, tăng tối đa điểm ngọt theo mọi hướng, phần khung của vợt Yonex Astrox 100 Game VA vuông hơn nên khi cầu chạm mặt vợt ở những điểm khác nhau trên mặt vợt vẫn mang lại cảm giác đánh tốt nhất.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ROTATIONAL GENARATOR SYSTEM: </strong>Là công nghệ theo thuyết đối trọng. Trọng lực được phân bổ ở đầu, đoạn nối chữ T và phần đầu vợt Yonex Astrox 100. Việc phân bổ như vậy giúp cho cây vợt được đồng đều, hỗ trợ tốt nhất cho vợt sau khi đánh xong quả cầu trước và chuẩn bị cho pha đánh cầu tiếp theo dễ dàng hơn. Điều này giúp cho việc dù đang cầm vợt nặng đầu nhưng vẫn mang đến cảm giác cân bằng, thoải mái.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>-</strong> <strong>ENERGY BOOST CAP</strong> là công nghệ mới nhất và được sử dụng hầu hết trên các dòng vợt cao cấp của Yonex hiện nay. Công nghệ này thiết kế nắp chụp cán vợt có hình dạng độc đáo giúp tối đa hóa hiệu suất thân vợt. Mặt trước cho phép thân vợt uốn cong, trong khi đường cong hai bên giúp ổn định mặt vợt bằng cách ngăn thân vợt vặn xoắn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Công nghệ SLIM SHAFT</strong> của hãng Yonex được tích hợp lên đũa vợt cho ra một thiết kế mỏng, từ đó đem lại hiệu suất uốn trục cao cho từng đường cầu nhanh và thoát trong không khí, giảm hệ số cản gió cho tốc độ ra vợt nhanh hơn cùng khả năng truyền lực từ cổ tay tới mặt vợt một cách chính xác.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- </strong><strong>BUILT-IN T-JOINT</strong> là công nghệ được sử dụng nhiều trên các cây vợt cầu lông Yonex với công dụng tăng sức mạnh giữa khung và thân vợt. Công nghệ này được ứng dụng lên khớp nối chữ T, sử dụng vật liệu carbon cứng cáp giúp tăng cường độ ổn định cho khung và giảm thiểu tình trạng xoắn vợt khi thực hiện những pha cầu nhanh, liên tục từ đó tăng cường khả năng kiểm soát.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>4. Đối tượng phù hợp với Vợt cầu lông Yonex Astrox 100 Game VA</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Vợt cầu lông Yonex Astrox 100 Game VA  dành cho người chơi yêu thích lối chơi tấn công mạnh mẽ từ cuối sân nhưng vẫn linh hoạt để phòng thủ, điều cầu và xử lý các tình huống trên lưới.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- </span></span><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Phiên bản 4U dành cho người trung bình phù hợp với những người đang trong giai đoạn phát triển lực tay, những người chơi có lối đánh tấn công, hoặc những người ưu tiên tốc độ và sự linh hoạt trong lối chơi công thủ toàn diện.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Phiên bản 3U dành cho những người chơi ở trình độ trung bình khá trở lên, những người đã có kinh nghiệm chơi cầu sở hữu lực cổ tay tốt và kỹ thuật vững vàng.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'vot-cau-long-yonex-astrox-100-game-va', TRUE, NOW(), NOW());
