INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (17, 1, 1, 'Vợt cầu lông Yonex Arcsaber 2 Feel', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">1. Giới thiệu Vợt cầu lông Yonex Arcsaber 2 Feel</span></span></strong></h2>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Vợt cầu lông Yonex Arcsaber 2 Feel - Black / Green</span></span></em></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Với chất liệu HT Graphite giúp vợt có độ căng tối đa tới 20-30 lbs đảm bảo độ bền cao, trọng lượng nhẹ để đảm bảo độ cơ động và linh hoạt. Thiết kế đũa vợt siêu mỏng, mang lại tối đa khả năng cắt gió để tăng tốc độ vung vợt trong không khí, tạo ra sức mạnh nhanh chóng và khả năng xử lý cầu siêu nhanh. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bên cạnh đó, vợt còn được tích hơp thêm công nghệ Isometric giúp mở rộng điểm ngọt, hạn chế những cú đánh lệch tâm, cho ra những đường cầu chính xác hơn. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Ngoài ra các bạn có thể tham khảo thêm những cây <a href="https://shopvnb.com/vot-cau-long-yonex.html">vợt cầu lông Yonex</a> đang được bán tại Shop VNB để có thêm nhiều sự lựa chọn.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số Vợt cầu lông Yonex Arcsaber 2 Feel</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thương hiệu: Yonex</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cứng: Siêu dẻo </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Màu sắc: Black / Pink</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu: HT Graphite</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cân bằng: Cân bằng</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng: 4U</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chu vi cán vợt: G5,6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Mức căng dây tối đa: 20 - 30LBS</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ tích hợp trên Vợt cầu lông Yonex Arcsaber 2 Feel</strong></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ISOMETRIC</strong>: Công nghệ thiết kế hình vuông giúp đảm bảo tính tương đồng về độ dài và góc của các dây dọc cũng như dây ngang, tăng tối đa điểm ngọt theo mọi hướng, thiết kế khung lớn hơn nên khi cầu chạm mặt vợt ở những điểm khác nhau trên mặt vợt vẫn mang lại cảm giác đánh tốt nhất.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- AERO-BOX FRAME: </strong>kết hợp giữa kiểu khung hàng không Aero Frame và khung BOX Frame để tạo nên một cấu trúc độc đáo để giảm lực cản của gió nhưng vẫn giữ được độ bền cao của khung vợt. Khung AeroBox đảm bảo đem lại độ xoáy nhanh hơn và cảm giác chắc chắn trong từng cú đánh khi tiếp mặt tiếp xúc với cầu.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- SUPER SLIM SHAFTS</strong> là công nghệ được thiết kế bởi nhà Yonex với đũa vợt siêu mỏng, tối đa khả năng cắt gió để tăng tốc độ vung vợt trong không khí, tạo ra sức mạnh nhanh chóng và khả năng xử lý cầu siêu nhanh trên lưới.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- CONTROL SUPPORT CAP:</strong> là công nghệ Yonex áp dụng lên nắp vợt cầu lông giúp bề mặt rộng hơn, phẳng hơn, cải thiện độ bám để tăng khả năng kiểm soát vợt.</span></span></p>
<h2 style="text-align:justify"><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px"><strong>4. Đối tượng phù hợp với Vợt cầu lông Yonex Arcsaber 2 Feel</strong></span></span></h2>
<p style="text-align:justify"><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Vợt cầu lông Yonex Arcsaber 2 Feel với thiết kế đũa siêu dẻo, điểm cân bằng ở mức cân bằng, phù hợp với các bạn thích lối đánh công thủ toàn diện.</span></span></p>
<p style="text-align:justify"><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Vợt thích hợp cho những người có cổ tay chưa tốt, người mới tập chơi đều có thể dễ dàng làm quen, kiểm soát.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'vot-cau-long-yonex-arcsaber-2-feel', TRUE, NOW(), NOW());
