INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (26, 1, 2, 'Vợt cầu lông Lining Halbertec 1000 chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">1. Giới thiệu Vợt cầu lông Lining Halbertec 1000</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/vot-cau-long-lining-halbertec-1000-chinh-hang.html">Vợt cầu lông Lining Halbertec 1000</a> tiếp nối sự thành công của các dòng vợt Lining Halbertec đang làm mưa làm gió trên thị trường cầu lông thời gian vừa qua.  Là cây vợt nằm trong phân khúc giá rẻ được ra mắt vào nửa cuối năm 2025, đánh dấu một bước đi chiến lược của thương hiệu, hướng đến người chơi tìm kiếm sự chính xác và tinh tế vượt trội.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="0VGbFpWB5hs" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/0VGbFpWB5hs/maxresdefault.jpg);"></div></div></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đũa vợt mỏng chỉ 6.8mm kết hợp với hệ thống HDF đặc trưng mang đến tốc độ vung vợt nhanh như chớp nhưng vẫn duy trì được sự êm ái, ổn định và thoải mái. Cây vợt có độ chính xác cao này sở hữu công nghệ STD Carbon/Control và khung vợt sợi carbon bền bỉ, mang lại độ ổn định và độ phản hồi vượt trội, hoàn toàn phù hợp với phong cách chơi chiến thuật, tập trung vào kiểm soát cầu.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="skLZ8VItMc4" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/skLZ8VItMc4/maxresdefault.jpg);"></div></div></span></span></p>
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">2. Thông số kĩ thuật Vợt cầu lông Lining Halbertec 1000</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thương hiệu: Lining</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu: Carbon Fiber</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cứng: Trung bình</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cân bằng: 298mm+/-2mm</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng: 4U</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chu vi tay cầm: G6</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Sức căng tối đa: 11.5Kg</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Ngoài ra, các bạn có thể tham khảo qua các sản phẩm <a href="https://shopvnb.com/vot-cau-long-lining.html">vợt cầu lông Lining</a> khác tại ShopVNB với đa dạng mẫu mã để bạn có thể lựa chọn tùy thích theo sở thích và phong cách chơi của mình.</span></span></p>
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">3. Công nghệ tích hợp trên Vợt Cầu Lông Lining Halbertec 1000</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <strong>HIGH MODULUS GRAPHITE: </strong>là công nghệ của vợt cầu lông Lining sử dụng chất liệu carbon cao cấp với độ bền bỉ và độ cứng cáp vượt trội, cho phép khung và thân vợt chịu lực tốt hơn, chịu được các tác động nhỏ để hạn chế tình trạng nứt gãy khi gặp va chạm cũng như là cải thiện mức căng chịu được của bộ khung. Giúp mức căng tối đa tăng lên đáng kể, đáp ứng các nhu cầu đan cao của người chơi.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Công nghệ hấp thụ sốc<strong> HDF SHOCK ABSORPTION SYSTEM </strong>được tích hợp lên khung vợt cầu lông Lining bằng việc trang bị một vật liệu hấp thụ ánh sáng công nghệ cao để giảm sốc. Sức mạnh tấn công sẽ được truyền đi mượt mà hơn và được giải phóng triệt để, giúp giảm chấn thương khi chơi thể thao một cách hiệu quả.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- 6.8MM HIGH-MODULUS SLIM SHAFT</strong> là công nghệ của hãng Lining được áp dụng lên đũa vợt. Thiết kế với trục vợt mỏng, chỉ có đường kính 6.8mm là minh chứng cho độ chính xác kỹ thuật. Được chế tạo từ than chì có mô đun cao, trục thanh mảnh này mang lại sự cân bằng hoàn hảo giữa tính linh hoạt và sức mạnh. Cấu hình mỏng của nó đảm bảo khả năng phản hồi vợt nhanh để có được những pha xử lý tốc độ, trong khi than chì có mô đun cao đảm bảo độ bền cho đũa vợt.</span></span></p>
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">3. Đối tượng phù hợp với Vợt cầu lông Lining Halbertec1000</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Vợt cầu lông Lining Halbertec Motor Pro phù hợp với người chơi ở nhiều trình độ khác nhau từ phong trào đến bán chuyên nghiệp, lực cổ tay và trình độ ở mức trung bình trở lên.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Halbertec 1000 dành cho người chơi yêu thích lối chơi công thủ toàn diện, thiên về sự chính xác, tinh tế trong các pha điều cầu, bắt lưới.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'vot-cau-long-lining-halbertec-1000-chinh-hang', TRUE, NOW(), NOW());
INSERT INTO product_variants (id, product_id, color_id, size_id, sku_code, price, sale_price, updated_at) VALUES (49, 26, NULL, NULL, 'VNB026782-ONESIZE-Default', 1056000, 880000, NOW());
