INSERT INTO product_specifications (id, product_id, name, value) VALUES (84, 31, 'AERONAUT TECHNOLOGY PLATFORM', 'Cây vợt cầu lông Lining Aeronaut 6000i được xây dựng trên nền tảng công nghệ hàng không, có các rãnh thoát khí độc đáo được tích hợp vào đầu vợt, điều này làm giảm sức cản không khí khi vung vợt giúp người dùng tạo ra những cú đánh tốc độ hơn');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (85, 31, 'High Tensile Slim Shaft', 'Thiết kế trục mỏng trên cùng 7,0mm cung cấp độ bền cực cao và khả năng điều khiển tự do dễ dàng hơn. Cân bằng hoàn hảo với trọng lượng vợt và quán tính chuyển động kết hợp khí động học. Trục mỏng có độ bền cao làm trụ cột của sức mạnh và kỹ năng, giải phó');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (86, 31, 'MPCF REINFORCING TECHNOLOGY', 'Li-Ning thực hiện bước bổ sung để tránh sự không hoàn hảo đôi khi do xử lý máy của các vợt khác. Bằng cách thực hiện các sợi carbon nhiều lớp, vợt được chế tạo với sức mạnh và tuổi thọ cao trong tâm trí');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (87, 31, 'HOT MELT', 'Quy trình độc quyền của trộn kỹ các loại nhựa với sợi carbon để đảm bảo tất cả các vợt của Lining được sản xuất một cách thống nhất. Điều này cung cấp sức mạnh tối ưu và hiệu suất phù hợp cho dù bạn chọn vợt nào');
INSERT INTO resources (id, public_id, url, type, owner_type, owner_id, sort_order, created_at) VALUES (125, 'goodminton/products/vot-cau-long-lining-aeronaut-6000i-thumbnail', 'https://res.cloudinary.com/dyrppweev/image/upload/v1778157541/goodminton/products/vot-cau-long-lining-aeronaut-6000i-thumbnail.webp', 'IMAGE', 'PRODUCT_THUMBNAIL', 31, 0, NOW());
INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (32, 1, 2, 'Vợt cầu lông Lining Aeronaut 6000C', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Vợt cầu lông Lining Aeronaut 6000C</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Dòng vợt Aeronaut của Lining đã quá nổi tiếng trong giới cầu lông, được cải tiến từ công nghệ Air-stream và ra mắt từ năm 2019 được rất nhiều các vận động viên top đầu thế giới sử dụng và gặt hái được rất nhiều thành công. Điểm nổi bật riêng biệt tạo nên cho dòng sản phẩm này có thiết kế mới với những rãnh thoát khí giúp tăng tốc độ tấn công và tốc độ vung vợt khi chơi cầu. Đặc biệt trong tháng 9/2020 vừa qua một siêu phẩm tàm trung mới đã được cho ra mắt đó chính là vợt cầu lông Lining Aeronaut 6000C - Người em ruột của siêu phẩm Aeronaut 9000C.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="gQ7YY6nrYKM" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/gQ7YY6nrYKM/maxresdefault.jpg);"></div></div></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/vot-cau-long-lining-aeronaut-6000c.html">Vợt cầu lông Lining Aeronaut 6000C</a> là cây vợt cầu lông cận cao cấp tiếp nối series dòng vợt aeronaut với trọng lượng 3U, thân vợt cứng cùng độ nặng đầu 295 mm thích hợp cho người chơi nhanh, có kỹ năng chuyển đổi linh hoạt giữa tấn công và phòng thủ.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Vợt cầu lông cận cao cấp Lining Aeronaut 6000C được xây dựng trên nền <strong>Aeronaut Technology</strong> ( công nghệ hàng không ), có các rãnh thoát khí độc đáo được tích hợp vào đầu vợt, điều này làm giảm sức cản không khí khi vung vợt giúp người dùng tạo ra những cú đánh tốc độ hơn. Phù hợp cho người chơi có lối đánh thiên công, tốc độ nhanh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Li-Ning Aeronaut 6000C (COMBAT Series) có điểm cân bằng hơi nặng đầu và trọng lượng 3U, thích hợp cho những người chơi đam mê tấn công, hiếu chiến muốn tìm kiếm sức mạnh tối đa để tấn công áp đảo đối thủ.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thân vợt có độ cứng trung bình cho cảm giác vung vợt nhanh và chắc chắn hơn. Hạn chế được tối đa cảm giác rung lắc hay xoắn vặn vợt sau mỗi cú đánh và cảm giác ổn định hơn dù điểm tiếp xuc giữ vợt và cầu không nằm trong điểm ngọt của mặt khung. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Lining luôn có những thiết kế vô cùng bắt mắt với những chi tiết hiện đại, màu sắc vừa ấn tượng, vừa hài hòa, chất sơn cao cấp cùng thời gian, Aeronaut 6000C cũng vậy. Nổi bật với màu sơn xanh đen, mạnh mẽ và mang đến cảm giác chắc chắn, ổn định trong thiết kế các chi tiết cùng màu đỏ, đen. Đây là cây vợt thật sự vượt ngoài những gì bạn mong đợi và đầu tư vào.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số vợt cầu lông Lining Aeronaut 6000C</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Độ cứng: Trung bình</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Khung vợt: Military Grade Carbon Fiber</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thân vợt: Military Grade Carbon Fiber</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng: 87g (W3)</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Điểm cân bằng: 295 mm (Hơi nặng đầu)</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chu vi cán vợt: S1 (G6)</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chiều dài vợt: 675 mm</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chiều dài cán vợt: 200 mm</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Điểm swingweight: 88 kg/cm2</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Sức căng: Dọc 24-28 lbs, ngang 26-30 lbs (Tối đa 12,7kg)</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Màu sắc Aeronaut 6000C: Xanh đen/ Đỏ/ Đen</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ áp dụng lên vợt cầu lông Lining Aeronaut 6000C</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- WING STABILIZER:</strong> Giới thiệu thiết kế công nghệ hàng không giải phóng bộ nhớ hiệu suất kim loại và cải thiện kiểm soát trên các nét. Cây vợt cầu lông Lining Aeronaut 6000C ứng dụng chéo của công nghệ hàng không trên các sản phẩm Li Ning là cơ chế ổn định cánh. Nó sẽ điều khiển phục hồi khung chính xác tại thời điểm biến dạng và để hạn chế rung do sóng rung từ mỗi cú đánh. Hiệu suất chống xoắn của vợt được cải thiện trong điều kiện căng thẳng cao và mang lại một cú đánh thứ hai nhanh chóng, chính xác và ổn định.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- MPCF REINFORCING TECHNOLOGY: </strong>Li-Ning thực hiện bước bổ sung để tránh sự không hoàn hảo đôi khi do xử lý máy của các vợt khác. Bằng cách thực hiện các sợi carbon nhiều lớp, vợt được chế tạo với sức mạnh và tuổi thọ cao trong tâm trí.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- DYNAMIN-OPT-IMUM FRAME</strong>: Tất cả các thiết kế tối ưu hóa vòng cải thiện cấu trúc cơ khí vợt cho hệ thống tấn công và phòng thủ hiệu quả hơn. Điểm ngọt kéo dài lên trên và điểm nhấn được di chuyển cao hơn. Khu vực phòng thủ hiệu quả được mở rộng để tăng khả năng phòng thủ lên tối đa bằng khung tối ưu động. Vận tốc đánh được cải thiện đáng kể với diện tích khung mở rộng và tăng cường độ nảy.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- AEROTEC BEAM SYSTEM</strong>: Dựa trên hệ thống chùm aerotec, hỗ trợ tính toán tiên tiến và thu thập dữ liệu thực hành, cấu trúc và hình dạng của phần khung trên cây vợt cầu lông đẳng cấp Aeronaut 6000C có hệ số cản cực thấp và cường độ cao, tạo nên hiệu suất của người chơi trong pha đánh khác nhau.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- TURBO NANO</strong>: Ứng dụng của công nghệ nanomet nâng cấp quy trình sản xuất vợt một cách toàn diện và do đó phá vỡ giới hạn về cường độ đánh. Công nghệ Li-Ning TB Nano ban đầu liên kết các sợi carbon và nhựa đến mức chưa từng có với sự hoàn hảo tự nhiên. Ổn định hơn, mỏng hơn và cứng hơn, vì vậy ta có một cây vợt lý tưởng ở đây với mức tăng 20% sức mạnh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- HOT MELT: </strong>Quy trình độc quyền của trộn kỹ các loại nhựa với sợi carbon để đảm bảo tất cả các vợt của Lining được sản xuất một cách thống nhất. Điều này cung cấp sức mạnh tối ưu và hiệu suất phù hợp cho dù bạn chọn vợt nào.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- STABILIZED ELASTIC SHAFT: </strong>nhà sản xuất lấp đầy các trục mỏng của vợt bằng các sợi aramid tương tự được tìm thấy trong áo giáp và mũ bảo hiểm. Những sợi tổng hợp chịu nhiệt và mạnh mẽ này cung cấp độ linh hoạt và độ bền hàng đầu thế giới. Đây là một cách khác giúp vợt Li-Ning bền và chắc chắn hơn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- STABILIZED TORSSION ANGLE</strong>: Góc xoắn ổn định đảm bảo độ đàn hồi cao cho cây vợt đánh cầu lông Lining Aeronaut 6000C. Nó giúp tạo ra cuộc tấn công chất lượng cao trở lại, mặc dù điểm đánh đã rời khỏi vùng điểm ngọt.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- LOCKING CUBIC: </strong>Những grommets có rãnh mỏng này khóa vào và bảo vệ phần tiếp xúc của dây dọc theo các cạnh của vợt. Chúng giúp giảm sốc để làm cho cú đánh của bạn chính xác hơn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- FRTP TECH: </strong>Bằng cách thay đổi điểm giật của trục, vợt của chúng tôi nhanh chóng uốn cong và bật trở lại vị trí, vì vậy bạn đã sẵn sàng cho cú vô-lê và tấn công liên tục.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>4. Đối tượng phù hợp với vợt cầu lông Lining Aeronaut 6000C</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Cây vợt cầu lông xịn Lining Aeronaut 6000C với trọng lượng 3U độ nằng đầu 295<strong> </strong>mm<strong> </strong>phù hợp cho người chơi trong cả đánh đơn và cả đánh đòi hỏi cổ tay phải khỏe.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đây là một cây vợt nổi trội với khả năng tốc độ, đánh nhanh từ công nghệ Aeronaut mang đến. Ngoài ra khả năng smash cầu mà cây vợt đem lại vô cùng hoàn hảo.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Lining Aeronaut 6000C là cây vợt phù hợp với người có lực cổ tay khá, tốt, người chơi phong trào tầm cao, bán chuyên, chuyên nghiệp, trình độ khá, giỏi sẽ phát huy được hết hiệu năng mà vợt đem đến.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'vot-cau-long-lining-aeronaut-6000c', TRUE, NOW(), NOW());
