INSERT INTO product_specifications (id, product_id, name, value) VALUES (141, 51, 'POWER RING PRO', 'Đây là một công nghệ nâng cấp trên Victor DriveX 12 O tăng cường độ cứng và tính đàn hồi ở khu vực khớp nối chữ T (T-joint) hoặc khung vợt. Giúp tăng trọng lượng swing (swingweight), nâng cao khả năng phản hồi của vợt khi tiếp xúc cầu và trực tiếp gia tăn');
