INSERT INTO product_specifications (id, product_id, name, value) VALUES (173, 63, 'TRU CUSHION+', 'Công nghệ đệm tiên tiến giúp triệt tiêu lực va chạm khi tiếp đất, đồng thời chuyển đổi phần năng lượng đó thành lực phản hồi cho bước di chuyển kế tiếp. Nhờ vậy, các pha bật nhảy và tăng tốc trở nên êm ái hơn, giảm áp lực đáng kể lên gót chân và khớp gối');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (174, 63, 'TRU FOAM', 'Lớp vật liệu đệm có trọng lượng nhẹ và độ thông thoáng cao, giúp tối ưu sự linh hoạt khi di chuyển liên tục. Cấu trúc này mang lại cảm giác dễ chịu suốt thời gian dài thi đấu, hạn chế tình trạng nặng chân hoặc mỏi cơ');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (175, 63, 'Tấm Carbon Graphite', 'Phần khung gia cường đặt ở giữa bàn chân giúp tăng độ ổn định và hạn chế xoắn vặn khi đổi hướng đột ngột. Đồng thời, cấu trúc carbon còn hỗ trợ cải thiện độ bật và khả năng hoàn trả năng lượng trong từng bước chạy');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (176, 63, 'TPU gia cố hai bên thân giày', 'Chi tiết TPU được bố trí dọc hai bên hông nhằm tăng độ chắc chắn khi di chuyển ngang. Thiết kế này giúp bàn chân giữ đúng vị trí, giảm hao hụt lực và nâng cao độ phản hồi khi xử lý các tình huống cầu nhanh');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (177, 63, 'Hệ thống chống xoắn kép', 'Cơ chế ổn định kép ở khu vực midfoot giúp kiểm soát chuyển động hiệu quả hơn trong các pha tiếp đất và đổi hướng tốc độ cao, từ đó hạn chế nguy cơ lật cổ chân và tăng sự tự tin khi thi đấu');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (178, 63, 'Cấu trúc upper thoáng khí', 'Thân giày cầu lông Yonex Cumulo sử dụng vật liệu kết hợp lưới kỹ thuật, tối ưu khả năng lưu thông không khí. Nhờ đó, bàn chân luôn khô ráo, giảm tích tụ mồ hôi và duy trì cảm giác thoải mái trong suốt trận đấu');
