INSERT INTO product_specifications (id, product_id, name, value) VALUES (187, 66, 'Toe Assist Shape', 'Thiết kế tập trung vào ngón chân giúp giảm áp lực ở ngón chân cái, cũng như cung cấp sự hỗ trợ được cải thiện ở giữa bàn chân và gót chân để mang lại cảm giác vừa vặn, ổn định. Giảm tổn thất năng lượng, cho phép thực hiện các động tác chân nhanh chóng');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (188, 66, 'Feather Bounce Foam', 'Chất liệu đệm nhẹ được thiết kế để tạo độ đàn hồi tốt hơn cho mỗi bước đi');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (189, 66, 'Lateral Shell', 'Hãng sử dụng tấm cao su cứng có cấu trúc như một tấm vỏ sò được đặt ở vị trí hấp thụ nhiều lực nhất cũng như giảm rung lắc trong các pha chuyển động ngang');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (190, 66, 'Synchro-Fit Insole', 'Công nghệ sử dụng vật liệu nhằm tạo ra sự tiếp xúc an toàn giữa giày và bàn chân, giúp người chơi tiết kiệm năng lượng khi di chuyển liên tục');
