INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (67, 2, 1, 'Giày cầu lông Yonex Subaxia GT Men - Dark Gray chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Yonex Subaxia GT Men - Dark Gray</strong></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/giay-cau-long-yonex-subaxia-gt-men-dark-gray-chinh-hang.html">Giày cầu lông Yonex Subaxia GT Men - Dark Gray</a> là phiên bản kế nhiệm của mẫu giày Grpht Thrttl (hay Graphite Throttle), được ra mắt hồi đầu năm nay. Đây là một mẫu giày cao cấp dành cho những người chơi yêu cầu sự bùng nổ tối đa, độ ổn định và sự thoải mái. Sản phẩm mới này của Yonex được thiết kế để tối ưu hóa mọi cú nhảy, cú đánh và cú tiếp đất thành sức mạnh, mang lại hiệu suất và tốc độ cao hơn mà không ảnh hưởng đến khả năng kiểm soát hoặc sự thoải mái.</span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="NZyWSF7cd2k" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/NZyWSF7cd2k/maxresdefault.jpg);"></div></div></span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Giày Subaxia GT Men cũng có hệ thống phần trên mới. Nhìn từ trên xuống, nó trông khá chắc chắn hoạt động rất tốt. Subaxia được thiết kế để giữ chặt chân bạn trong quá trình di chuyển, và trong các thử nghiệm, nó đã hoạt động hoàn hảo.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Giày Subaxia sử dụng đế ngoài Radial Blade phổ biến và đã được chứng minh hiệu quả, mang đến cảm giác rất bám trên nhiều bề mặt khác nhau. Các rãnh sâu hơn cho phép chuyển động linh hoạt hơn một chút, giúp tăng độ bám trên nhiều loại bề mặt khác nhau. Điều này tương tự như cách hoạt động của lốp xe - một chút trượt có kiểm soát thực sự có thể cải thiện độ bám đường.</span></span></p>
<p style="text-align: center;"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><div style="text-align:center"><div class="youtube-placeholder" data-video-id="T359CAR0QaI" onclick="loadVideo(this)" style="background-image: url(https://img.youtube.com/vi/T359CAR0QaI/maxresdefault.jpg);"></div></div></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Ngoài ra các bạn có thể tham khảo thêm nhiều mẫu <a href="https://shopvnb.com/giay-cau-long-yonex.html">giày cầu lông Yonex</a> khác với nhiều mẫu mã cực kỳ độc đáo và đẹp mắt tại ShopVNB nhé.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Kết cấu tổng thể Giày cầu lông Yonex Subaxia GT Men - Dark Gray</strong></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thương hiệu: Yonex</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Màu sắc: Dark Gray</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu thân giày (Upper): Synthetic Fiber</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đế giữa (Midsole): Synthetic Resin</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đế ngoài (Outsole): Rubber Sole</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bảng size giày Yonex:</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ và các ưu điểm nổi bật trên Giày cầu lông Yonex Subaxia GT Men - Dark Gray</strong></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- GRPHT THRTTL: </strong>Công nghệ đệm thế hệ mới, mang đến khả năng giảm chấn vượt trội và lực đẩy bùng nổ, hỗ trợ tối đa cho các pha bật nhảy và smash uy lực, đặc biệt phù hợp với lối chơi tấn công hiện đại.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- RADIAL BLADE SOLE</strong> là công nghệ đế giày có độ bám sân mới nhất của nhà Yonex với những cải tiến vượt bậc so với loại đế lục giác. Hoa văn hình phi tiêu 4 cánh của ninja được sắp xếp một cách tỉ mỉ giúp phân tán đều trọng lượng giày và cải thiện độ bám sân thêm 3%. Công nghệ này cho phép những pha chuyển hướng đột ngột được diễn ra một cách hiệu quả hơn, giúp người chơi hạn chế khả năng chấn thương ở chân do tình trạng trượt té gây ra.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Công nghệ tăng độ bám sân trong các chuyển động dọc, ngang và chéo, giúp người chơi tự tin đổi hướng di chuyển trên sân.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- DOUBLE RACHEL MESH: </strong>là loại lưới siêu mịn được phát triển trên các đôi giày cầu lông Yonex với tính năng cực kỳ nhẹ và bền, cung cấp khả năng trao đổi không khí để giải phóng độ ẩm gấp tám lần so với vải lưới thông thường. Điều này giúp đôi chân của bạn luôn trong trạng thái thoáng khí khi phải hoạt động trong nhiều giờ liền trên sân.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Durable Skin</strong>: Kết hợp tính linh hoạt giống như cao su với độ cứng của nhựa cứng, công nghệ DURABLE SKIN LIGHT<strong> </strong>của nhà Yonex dựa trên polyurethane đem lại một đôi giày cực nhẹ và vẫn giữ được cảm giác chắc chắn, vừa vặn.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Công nghệ DURABLE SKIN LIGHT</strong> của nhà Yonex sử dụng vật liệu Polyurethane có tính co giãn cao giống như cao su nhưng vẫn mang đặc tính cứng của nhựa. Được đặt ở phần trên thân giày để tạo cảm giác nhẹ nhàng trên đôi chân trong khi vẫn giữ được sự an toàn và vừa vặn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Inner Bootie</strong>: Lớp vải Bootie nối giữa thân giày và lưỡi gà với nhau cho cảm giác khi mang giày cầu lông vào sẽ rất êm ái và phần cổ giày sẽ ôm khít mắt cá chân.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Toe Assist Shape: </strong>Thiết kế tập trung vào ngón chân giúp giảm áp lực ở ngón chân cái, cũng như cung cấp sự hỗ trợ được cải thiện ở giữa bàn chân và gót chân để mang lại cảm giác vừa vặn, ổn định. Giảm tổn thất năng lượng, cho phép thực hiện các động tác chân nhanh chóng.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ROUND SOLE</strong> là công nghệ đế giày vượt trội của Yonex được thiết kế để hỗ trợ toàn diện cho việc di chuyển nhanh chóng và trơn tru, đảm bảo chuyển động linh hoạt và truyền năng lượng tối đa cho các chuyển động liên tục.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Công nghệ FEATHER BOUNCE FOAM </strong>làm cho đôi giày Yonex nhẹ hơn rất nhiều so với các dòng giày trên thị trường hiện nay. Công nghệ này sử dụng vật liệu nhẹ, có lực đẩy cao giúp người chơi dễ dàng di chuyển trên sân.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Feather Bounce Foam:</strong> Chất liệu đệm nhẹ được thiết kế để tạo độ đàn hồi tốt hơn cho mỗi bước đi.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Lateral Shell:</strong> Hãng sử dụng tấm cao su cứng có cấu trúc như một tấm vỏ sò được đặt ở vị trí hấp thụ nhiều lực nhất cũng như giảm rung lắc trong các pha chuyển động ngang.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Synchro-Fit Insole:</strong> Công nghệ sử dụng vật liệu nhằm tạo ra sự tiếp xúc an toàn giữa giày và bàn chân, giúp người chơi tiết kiệm năng lượng khi di chuyển liên tục.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'giay-cau-long-yonex-subaxia-gt-men-dark-gray-chinh-hang', TRUE, NOW(), NOW());
