INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (71, 2, 1, 'Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/giay-cau-long-yonex-shb-65z-va-women-grayish-beige-chinh-hang.html">Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige</a> mang đậm dấu ấn của Viktor Axelsen với phối màu trắng xanh nổi bật, thể hiện phong cách thi đấu bùng nổ, mạnh mẽ nhưng đòi hỏi độ ổn định tối đa. Phần thân giày được thiết kế liền mạch (Inner Bootie) giúp ôm sát bàn chân, giảm ma sát, hỗ trợ người chơi xoay chuyển, bật nhảy và tiếp đất nhẹ nhàng hơn ạ. Đế giày Round Sole và thiết kế Ergoshape giúp phân bổ lực đều, tăng khả năng cân bằng khi bạn di chuyển nhanh hoặc đổi hướng đột ngột.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đế giữa sử dụng nhựa tổng hợp, là nơi tích hợp các công nghệ chủ lực như Power Cushion+, Feather Bounce Foam và Power Graphite Sheet, giúp tăng cường khả năng đệm và ổn định. Trong khi đó, đế ngoài làm từ cao su non-marking mềm mại hơn thế hệ trước, tăng độ bám ngay từ lần đầu sử dụng. </span></span><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Bên cạnh đó, Yonex SHB 65Z VA Women sử dụng tông màu Grayish Beige (VA) vừa tinh tế vừa sang trọng, dễ phối hợp với mọi trang phục thi đấu, giúp bạn nổi bật và chuyên nghiệp hơn trên sân cầu.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số kỹ thuật của Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige</strong></span></span></h2>
<p style="text-align:justify"><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Thương hiệu: Yonex</span></span></p>
<p style="text-align:justify"><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Màu sắc: Grayish Beige</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Upper: Synthetic Leather</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Midsole: Synthetic Resin</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Outsole: Rubber Sole</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">* Bảng size giày Yonex:</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ được tích hợp trên Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- POWER CUSHION+: </strong>Bằng cách thêm một loại nhựa đàn hồi đặc biệt vào POWER CUSHION trong khi vẫn duy trì các đặc tính nhẹ nhàng giúp khả năng hấp thụ sốc cao được thực hiện. Ngoài ra, các rãnh ở đế được thiết kế theo mô hình mạng tinh thể với khoảng cách và độ sâu tối ưu, đạt được khả năng phục hồi tốt hơn. So với vật liệu đệm thông thường, POWER CUSHION＋ tự hào về khả năng hấp thụ sốc hơn 28% và lực đẩy mạnh hơn 62%. Thực nghiệm: Thả 1 quả trứng từ 12m xuống lớp đệm Power Cusion+ thì quả trứng không vỡ và bật lên lại 6m.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- POWER GRAPHITE LITE:</strong> Công nghệ giúp tăng và cải thiện độ ổn định và giảm độ xoắn sau khi tiếp đất.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- INNER BOOTIE:</strong> Lớp vải Bootie nối giữa thân giày và lưỡi gà với nhau cho cảm giác khi mang giày cầu lông vào sẽ rất êm ái và phần cổ giày sẽ ôm khít mắt cá chân.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- SEAMLESS UPPER</strong> là công nghệ được trang bị trên phần thân của các đôi giày Yonex bằng cách sử dụng một miếng da tổng hợp duy nhất bao phủ từ đầu bàn chân đến giữa bàn chân, giúp độ vừa vặn của giày được tăng cường và giảm căng thẳng không mong muốn.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Ergonomic Shaped Outsole:</strong> Đế giày được thiết kế theo hình dạng tự nhiên của bàn chân, cung cấp sự hỗ trợ, đệm và ổn định để tăng sự thoải mái, giảm mệt mỏi và ngăn ngừa chấn thương. Bằng cách tối ưu hóa độ cao của đế ngoài, tính linh hoạt được cải thiện và tích hợp với bàn chân khi uốn cong giúp tăng cường sức mạnh và hỗ trợ bước chân nhanh.</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>4. Ưu điểm của Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Giày cầu lông Yonex SHB 65Z VA Women - Grayish Beige được tối ưu nhờ Seamless Upper cùng Inner Bootie, mang lại cảm giác vững chãi mà không cần siết dây quá chặt. Thiết kế tinh tế, tối giản và hiện đại giúp đôi giày vừa đẹp mắt vừa chuyên nghiệp trên sân.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Phần đế Yonex 65Z VA được thiết kế với độ bám dính cực tốt, giúp người chơi di chuyển trên sân một cách trơn tru và ổn định, kể cả khi chuyển hướng liên tục. Điều này mang đến sự an tâm khi thực hiện các pha tấn công hoặc phòng thủ cần tốc độ và sự chính xác.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đây là mẫu giày toàn diện nhất mà Yonex từng sản xuất, phù hợp với cả vận động viên chuyên nghiệp lẫn người chơi phong trào muốn bảo vệ khớp chân, giảm áp lực gót, và nâng cao hiệu suất di chuyển.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'giay-cau-long-yonex-shb-65z-va-women-grayish-beige-chinh-hang', TRUE, NOW(), NOW());
