INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (74, 2, 1, 'Giày cầu lông Yonex 88 Dial 3 2025', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Yonex 88 Dial 3 2025</strong></span></span></h2>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/giay-cau-long-yonex-88-dial-3-2025.html">Giày cầu lông Yonex 88 Dial 3 2025</a> với công nghệ khóa BOA Fit độc quyền, chỉnh nhanh trong một cú xoay, ôm gọn từng chuyển động. Kết hợp cùng đế Power Cushion hỗ trợ tiếp đất êm ái, Power Cushion 88 Dial tiếp tục là lựa chọn hàng đầu để làm chủ những pha cầu tốc độ và linh hoạt.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Yonex 88 Dial 3 2025 là mẫu giày cao cấp mới nhất được Yonex ra mắt trong năm 2025, mang đến sự kết hợp hoàn hảo giữa thiết kế thời trang hiện đại và chất lượng đỉnh cao. Nổi bật với tông màu đen - xanh chuối, tạo nên vẻ ngoài cá tính và dễ nhận diện trên sân. Không chỉ gây ấn tượng về mặt thẩm mỹ, giày còn được chế tạo từ chất liệu bền bỉ, hỗ trợ vận động linh hoạt, phù hợp với mọi cường độ thi đấu.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Các bạn có thể tham khảo thêm các mẫu <a href="https://shopvnb.com/giay-cau-long-yonex.html">giày cầu lông Yonex</a> đang được bán tại Shop VNB để chọn ra mẫu giày ưng ý với sở thích của mình nhé.</span></span></p>
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Thông số kỹ thuật của Giày cầu lông Yonex 88 Dial 3 2025</strong></span></span></h2>
<p><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Thương hiệu: Yonex</span></span></p>
<p><span style="font-family:arial,helvetica,sans-serif"><span style="font-size:16px">- Màu sắc: Deep Green</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Surface: All-Court</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Upper: Synthetic Fiber</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Midsole: Synthetic Resin</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Outsole: Rubber Sole</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Size: 36 - 45</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bảng size giày cầu lông Yonex</span></span></p>
