INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (76, 2, 1, 'Giày cầu lông Yonex SHB 470CR', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Yonex SHB 470CR</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/giay-cau-long-yonex-shb-470cr.html">Giày cầu lông Yonex SHB 470CR</a> là dòng giày của Yonex luôn nổi tiếng với sự toàn diện, cung cấp sự êm ái, ôm chân, và khả năng chống lật cổ chân bảo vệ người sử dụng tốt nhất. Yonex SHB 470CR sử dụng gam màu nổi bật làm cho đôi giày trông vừa cá tính và trẻ trung.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bên cạnh những ưu điểm về mặt thiết kế, Giày Yonex SHB 470CR được đánh giá cao bởi công nghệ Power Cushion độc quyền của Yonex giúp hấp thụ sốc và phục hồi nhanh trong trên từng bước di chuyển. Đế giày được nâng cấp để bám sân tốt hơn mang đến sự tự tin trong nhưng pha di chuyển nhanh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- onex SHB 470CR với phiên bản lần này dành cho những người chơi phong trào và nghiệp dư đang cần một đôi giày đáp ứng được các tiêu chí cần thiết và mức giá vừa phải. Nếu bạn đang cần mua giày cầu lông vừa đẹp mắt vừa chất lượng thì đây sẽ là một lựa chọn xứng đáng dành cho bạn. </span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><em>Giày cầu lông Yonex SHB 470CR - Hồng</em></span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><em>Giày cầu lông Yonex SHB 470CR - Trắng vàng</em></span></span></p>
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><em>Giày cầu lông Yonex SHB 39EX - Xanh bạc hà</em></span></span></p>
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">2. Thông số kỹ thuật của Giày cầu lông Yonex SHB 470CR</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">– Thương hiệu: Yonex</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">– Thân giày/ Upper: Da tổng hợp + lưới thoáng khí</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">– Đế giữa/ Midsole: Power Cushion + EVA Midsole</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">– Đế ngoài/ Outsole: Cao su chống trượt Non-Marking</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">– Bảng size lựa chọn:</span></span></p>
<h2 style="text-align:justify"><strong><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">3.Công nghệ và các ưu điểm nổi bật trên Giày cầu lông Yonex SHB 470CR</span></span></strong></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- POWER CUSHION: </strong>Là công nghệ độc quyền được phát triển lâu đời trên hầu hết các dòng giày Yonex. Về cơ bản, công nghệ này hoạt động dựa trên sự kết hợp về mặt chất liệu giữa gót giày và đế giữa giày. để tạo ra một vật liệu mềm, có độ đàn hồi tốt hơn cả Urethane với khả năng hấp thụ sốc và các lực tác động, giải phóng các lực này một cách thoải mái và đều đặn, đồng thời còn chuyển các lực dư thừa phát sinh sau mỗi chuyển động trước đó để chuyển thành lực cung cấp cho các chuyển động tiếp theo để có thể trợ lực cho bàn chân, tạo bước đà nhanh để di chuyển và bật nhảy cao hơn. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- Ergoshape:</strong> Là một thiết kế độc quyền của Yonex, tập trung vào phần mũi giày để mang lại sự thoải mái và ổn định hơn cho người chơi cầu lông. Công nghệ này giúp ôm sát bàn chân, đặc biệt là ở khu vực ngón chân và mu bàn chân, giảm căng thẳng khi di chuyển nhanh và mạnh, đồng thời hỗ trợ người chơi có những bước di chuyển linh hoạt và chính xác hơn. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- NON-MARKING:</strong> Là công nghệ đế không để lại dấu vết khi thi đấu trên mặt sân thảm, sàn bằng phẳng. Đây là công nghệ của hãng Lining thường được sử dụng trên các đôi giày cầu lông. Công nghệ này sử dụng chất liệu cao su cao cấp để làm phần đế ngoài, gia tăng độ bền, đặc biệt là độ bám sàn cao và không để lại dấu vết trên mặt sân thi đấu. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- INNER BOOTIE:</strong> Lớp vải Bootie nối giữa thân giày và lưỡi gà với nhau cho cảm giác khi mang giày cầu lông vào sẽ rất êm ái và phần cổ giày sẽ ôm khít mắt cá chân.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'giay-cau-long-yonex-shb-470cr', TRUE, NOW(), NOW());
