INSERT INTO product_specifications (id, product_id, name, value) VALUES (231, 79, 'DOUBLE RUSSEL MESH', 'sử dụng chất liệu lưới giúp thông thoáng giày và giải phóng độ ẩm một cách hiệu quả. Sợi lưới siêu nhẹ và bền bỉ, giúp giữ cho chân luôn khô ráo và thoải mái');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (232, 79, 'EXTRA CUSHIONING', 'lớp đệm Phylon được bổ sung vào gót chân để tăng cường sự êm ái khi di chuyển, giúp giảm áp lực lên bàn chân, đặc biệt là vùng gót chân');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (233, 79, 'TRU CUSHION SOCKLINER', 'công nghệ được tích hợp lên phần lót giày cầu lông Yonex Skill 5 nhằm cung cấp khả năng hấp thụ sốc, phục hồi nén nhanh chóng và khả năng phục hồi cao ở phần đệm');
INSERT INTO product_specifications (id, product_id, name, value) VALUES (234, 79, 'FLEX BACK ACTION', 'công nghệ với cơ chế uốn cong đặc biệt, chúng được tạo ra để tạo điều kiện cho các các chuyển động nhanh chóng và lối chơi linh hoạt');
