INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (80, 2, 1, 'Giày cầu lông Yonex Hy Ultra', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12" data-field="bai_viet">
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Yonex Hy Ultra</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <strong><a href="https://shopvnb.com/giay-cau-long-yonex-hy-ultra.html">Giày cầu lông Yonex Hy Ultra</a></strong> là một trong những dòng giày cầu lông giá rẻ được nhà Yonex cho ra mắt gần đây. Với sự đa dạng về màu sắc, tha hồ để cho các bạn lựa chọn, đặc biệt là phù hợp với các bạn học sinh, sinh viên, những người chơi phong trào yêu thích bộ môn cầu lông.</span></span></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - Indigo Marine/White</span></span></em></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - Dark Cobalt/White/Aquarius</span></span></em></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Giày Yonex Hy Ultra có tông màu nổi bật và hiện đại, tạo điểm nhấn khi mang lên sân. Với thiết kế vô cùng tỉ mỉ và trau chuốt, tin chắc rằng đây sẽ là đôi giày đáng cho anh em lông thủ sử dụng.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Yonex Hy Ultra được sản xuất với form giày cứng cáp, giữ bàn chân ổn định trong mọi chuyển động trên sân, tránh những chấn thương ngoài ý muốn. Ngoài ra, ở phần bề mặt giày Yonex Hy Ultra còn được bổ sung nhiều lỗ nhỏ, giúp giày luôn khô ráo, thông thoáng, hạn chế gây ra những mùi khó chịu.</span></span></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - White/Jade Green</span></span></em></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - Lava Red/Night Shadow</span></span></em></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - Sunset/Grey</span></span></em></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - Honey Mustard/Night Shadow</span></span></em></p>
<p style="text-align:center"><em><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Giày cầu lông Yonex Hy Ultra - White/Black</span></span></em></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bên cạnh đó, các bạn có thể tham khảo thêm những mẫu<strong> </strong><a href="https://shopvnb.com/giay-cau-long-yonex.html">Giày cầu lông Yonex</a> khác với nhiều mẫu mã đa dạng, chất lượng hiện đang có tại <strong>ShopVNB</strong></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Kết cấu tổng thể Giày cầu lông Yonex Hy Ultra</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thương hiệu: Yonex</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thân giày: Synthetic Fiber, lưới Russel đôi</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Lớp đệm: Tru Cushion, Lớp đệm tăng cường</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đế ngoài: Cao su, Non-marking, Flex Back Action</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">*Bảng size giày cầu lông Yonex:</span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3</strong>. <strong>Công nghệ và các ưu điểm nổi bật trên Giày cầu lông Yonex Hy Ultra</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- TRU SHAPE: </strong>Công nghệ này giúp giày cầu lông Yonex Hy Ultra có độ bền và độ dẻo cao hơn, cùng với đó là tăng khả năng chống trượt khi tiếp xúc với sàn đấu.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- EXTRA CUSHIONING:</strong> là công nghệ nổi trội của hãng Yonex với lớp đệm Phylon được bổ sung vào gót chân để tăng cường sự êm ái khi di chuyển, giúp giảm áp lực lên bàn chân, đặc biệt là vùng gót chân.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- RADIAL BLADE SOLE</strong> là công nghệ đế giày có độ bám sân mới nhất của nhà Yonex, với những cải tiến vượt bậc so với loại đế lục giác. </span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Hoa văn hình phi tiêu 4 cánh của ninja được sắp xếp một cách tỉ mỉ, giúp phân tán đều trọng lượng giày và cải thiện độ bám sân thêm 3%. Công nghệ này cho phép những pha chuyển hướng đột ngột được diễn ra một cách hiệu quả hơn, giúp người chơi hạn chế khả năng chấn thương ở chân do tình trạng trượt té gây ra.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">Công nghệ tăng độ bám sân trong các chuyển động dọc, ngang và chéo, giúp người chơi tự tin đổi hướng di chuyển trên sân.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- FLEX BACK ACTION</strong> là công nghệ được áp dụng ở phần giữa đế giày cầu lông Yonex Hy Ultra với cơ chế uốn cong đặc biệt, chúng được tạo ra để tạo điều kiện cho việc chuyển động nhanh chóng và lối chơi linh hoạt.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <strong>NON-MARKING</strong> là công nghệ đế giày không để lại dấu vết khi thi đấu trên mặt sân thảm, sàn bằng phẳng. Công nghệ này sử dụng chất liệu cao su cao cấp để làm phần đế ngoài, gia tăng độ bền, đặc biệt là độ bám sàn cao và không để lại dấu vết trên mặt sân thi đấu.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'giay-cau-long-yonex-hy-ultra', TRUE, NOW(), NOW());
