INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (86, 2, 2, 'Giày cầu lông Lining AYTV013-1 chính hãng', '<div class="rte product_getcontent">
<div id="content">
