INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (94, 2, 2, 'Giày cầu lông Lining AYTU001-9 chính hãng', '<div class="rte product_getcontent">
<div id="content">
