INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (109, 2, 3, 'Giày cầu lông Victor A550 LS  chính hãng', '<div class="rte product_getcontent">
<div id="content">
