INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (115, 2, 3, 'Giày cầu lông Victor C90 HP AM chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Giày cầu lông Victor A370 LI</strong></span></span></h2>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <a href="https://shopvnb.com/giay-cau-long-victor-c90-hp-ac-chinh-hang.html">Giày cầu lông Victor C90 HP AC</a> không chỉ là một đôi giày, mà còn là sự đầu tư vào sự thoải mái và an toàn cho đôi chân của bạn. Với công nghệ đệm NitroLite tiên tiến và hàng loạt tính năng hỗ trợ, C90 sẽ giúp bạn tận hưởng trọn vẹn niềm đam mê cầu lông mà không còn lo lắng về những tác động tiêu cực lên cơ thể.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Trọng lượng nhẹ và thiết kế màu trắng-xanh sành điệu, phù hợp cho người chơi tìm kiếm sự hỗ trợ tốt hơn, di chuyển nhanh hơn và thoải mái lâu dài. Giày có chiều cao đệm dày hơn bình thường, 12mm ở phía trước và 23mm ở phía sau. </span></span></p>
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Kết cấu tổng thể Giày cầu lông Victor C90 HP AM</strong></span></span></h2>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Thương hiệu: Victor</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Phần thân: TPU Skin + V-Tough + Double Mesh</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Phần đế giữa: EVA + Nylon Sheet + ENERGYMAX</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Phần đế ngoài cùng: VSR Rubber</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Bảng đo size giày cầu lông Victor:</span></span></p>
<h2><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>3. Công nghệ nổi bật trên Giày cầu lông Victor C90 HP AM</strong></span></span></h2>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- ENERGY MAX3.0: </strong>Victor sử dụng vật liệu có độ đàn hồi cao, tăng khả năng đàn hồi và hấp thụ sốc, có thể tăng cường đáng kể khả năng phục hồi tức thời, hấp thu sốc và tác dụng đệm giảm bớt chấn động khi tiếp đất.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- LS-S</strong> là công nghệ của hãng Victor được tích hợp lên mặt ngoài của giày cầu lông. Mặt ngoài của bàn chân trước được thiết kế bằng TPU có độ bền cao. Điều này tăng cường đáng kể sự ổn định trong quá trình chuyển hướng nhanh và đột ngột.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>- V-TOUGH</strong> là công nghệ chống mài mòn của hãng Victor được tích hợp bên trong giày cầu lông. Bề mặt bên trong của giày được làm bằng vật liệu chống mài mòn giúp kéo dài độ bền. Công nghệ chống mài mòn đã chứng minh khả năng chống mài mòn gấp 16 lần so với da PU thông thường.</span></span></p>
</div>
</a>
</div>
</div>
</div>
</div>', 'giay-cau-long-victor-c90-hp-am-chinh-hang', TRUE, NOW(), NOW());
