INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (121, 3, 1, 'Áo cầu lông Yonex TPM2899 - Oatmeal chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>Áo cầu lông Yonex TPM2899 - Oatmeal chính hãng - Form Áo Đẹp, Mát Mẻ, Thấm Hút Tốt Nhất Thị Trường</strong></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Áo cầu lông Yonex TPM2899 - Oatmeal chính hãng, giá tốt</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Áo cầu lông Yonex TPM2899 - Oatmeal chính hãng là một trong những mẫu <strong>áo cầu lông chính hãng</strong> nổi trội với chất liệu vải thấm hút tốt, mát mẻ, form áo đẹp, nhiều màu sắc và đặc biệt là có giá thành phải chăng đảm bảo sẽ làm các lông thủ cực ưng ý ngay từ lần đầu tiên sử dụng.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <em>Áo cầu lông Yonex TPM2899 - Oatmeal chính hãng xịn</em> với màu sắc bắt mắt, nổi trội khi sử dụng trên sân đấu. Đặc biệt mẫu áo thể thao cầu lông này chỉ được sản xuất với nhiều size để khách hàng có thể lựa chọn.</span></span></p>
