INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (123, 3, 1, 'Áo cầu lông Yonex TPM2736 - Cerise chính hãng', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>Áo cầu lông Yonex TPM2736 - Cerise chính hãng - Form Áo Đẹp, Mát Mẻ, Thấm Hút Tốt Nhất Thị Trường</strong></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Áo cầu lông Yonex TPM2736 - Cerise chính hãng, giá tốt</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Áo cầu lông Yonex TPM2736 - Cerise chính hãng là một trong những mẫu <strong>áo cầu lông chính hãng</strong> nổi trội với chất liệu vải thấm hút tốt, mát mẻ, form áo đẹp, nhiều màu sắc và đặc biệt là có giá thành phải chăng đảm bảo sẽ làm các lông thủ cực ưng ý ngay từ lần đầu tiên sử dụng.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- <em>Áo cầu lông Yonex TPM2736 - Cerise chính hãng xịn</em> với màu sắc bắt mắt, nổi trội khi sử dụng trên sân đấu. Đặc biệt mẫu áo thể thao cầu lông này chỉ được sản xuất với nhiều size để khách hàng có thể lựa chọn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Nếu lông thủ nào đang tìm kiếm cho mình 1 mẫu <strong>áo cầu lông</strong> thì sản phẩm Áo cầu lông Yonex TPM2736 - Cerise chính hãng là một sự lựa chọn vô cùng hợp lý. Mẫu áo cầu lông chính hãng này có chất lượng cực tốt được làm từ 100% Polyester không những cho người chơi khi mặc vào có cảm giác mát mẻ, dễ chịu, thấm hút mồ hôi tốt trong suốt quá trình chơi mà chiếc áo cầu lông này còn có độ bền bỉ rất cao dù bạn có giặt giũ mạnh cỡ nào thì đảm bảo màu của áo cũng sẽ không bị phai theo năm tháng.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đặc biệt khi so với các mẫu áo hiện có trên thị trường thì <strong>áo cầu lông chính hãng</strong> sẽ có chất lượng vải cùng thiết kế form áo đảm bảo cao cấp hơn rất nhiều, chắc chắn khi các lông thủ mặc vào là có thể cảm nhận được ngay.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chính vì vậy, nếu bạn đang tìm kiếm cho mình một chiếc <strong>áo cầu lông</strong> có chất lượng tốt nhất trên thị trường thì đảm bảo Áo cầu lông Yonex TPM2736 - Cerise chính hãng<strong> </strong>sẽ là một trong những gợi ý hoàn hảo nhất.</span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"></span></span></p>
<p><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Kết cấu tổng thể của áo cầu lông chính hãng</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Size: XS, S, M, L, XL, XXL</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu vải: 100% Polyester</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Loại áo: Áo chính hãng</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Tính năng:</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Thấm hút mồ hôi tốt.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Khô nhanh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Làm mát nhanh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống tĩnh điện</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống nhăn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Siêu bền bỉ.</span></span></p>
