INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (180, 3, 3, 'Áo hoodie lót bông Victor Vic01 - Xanh lá', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<p style="text-align:center"><span style="font-size:20px"><span style="font-family:arial,helvetica,sans-serif"><strong>Áo hoodie lót bông Victor Vic01 - Xanh lá - Hiện Đại, Đẳng Cấp, Giữ Ấm Cơ Thể Cực Tốt!</strong></span></span></p>
<h2 style="text-align:justify"><span style="font-size:20px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Áo hoodie lót bông Victor Vic01 - Xanh lá</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Ngoài trang bị cho mình bộ <strong>quần áo cầu lông</strong> để thi đấu trên sân thì chiếc áo khoác cầu lông cũng góp phần rất nhiều trong việc tăng sự đẳng cấp của người chơi và mẫu Áo hoodie lót bông Victor Vic01 - Xanh lá là một trong những gợi ý tốt nhất trên thị trường đấy nhé!</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Ngoài việc tôn lên sự đẳng cấp thì chiếc <strong>áo cầu lông đẹp</strong> (áo khoác) còn cho khả năng giữ ấm, giữ nhiệt cực tốt và giúp bảo vệ cơ thể khi đi ngoài gió lạnh hoặc sau khi vận động cần tránh bị không khí lạnh bên ngoài gây cảm lạnh có thể dẫn đến trúng gió, cảm cúm và nhiều biến chứng nguy hiểm khác,...</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chiếc <em>Áo hoodie lót bông Victor Vic01 - Xanh lá cao cấp</em> được thiết kế với kết cấu 2 lớp: Lớp da nỉ nhiều màu sắc bên ngoài không những cho khả năng chống lạnh ra thì việc chống nắng chống mưa cũng rất tốt. Lớp vải dù mỏng bên với vai trò giữ ấm cơ thể giúp người chơi luôn ở trong trạng thái ổn định nhất.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Áo hoodie lót bông Victor Vic01 - Xanh lá còn được phát hành với 4 size:</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">+ Size M: 50kg- 58kg.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">+ Size L: 59kg-68kg.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">+ Size XL: 69kg-78kg.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">+ Size XXL: 79kg-85kg.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"></span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"></span></span></p>
<h2 style="text-align:justify"><span style="font-size:20px"><span style="font-family:arial,helvetica,sans-serif"><strong>2. Kết cấu tổng thể của Áo hoodie lót bông Victor Vic01 - Xanh lá</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Sản phẩm: Áo hoodie lót bông Victor Vic01 - Xanh lá</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Loại áo: Áo khoác cầu lông</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu: 100% Polyester</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Size: M, L, XL, XXL</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Tính năng:</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống lạnh.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống nắng.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống mưa.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Giữ nhiệt tốt.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Chống nhăn.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">     + Siêu bền bỉ.</span></span></p>
