INSERT INTO products (id, category_id, brand_id, name, description, slug, is_visible, created_at, updated_at) VALUES (181, 4, 1, 'Quần cầu lông Victor 628 - Xanh biển', '<div class="rte product_getcontent">
<div id="content">
<div class="well product-well expanded">
<div class="row ababa">
<div class="col-md-12">
<p style="text-align:center"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>Quần cầu lông Victor 628 - Xanh biển - Co Dãn Tốt, Thấm Hút Hoàn Hảo, Bền Bỉ Sử Dụng Trong Một Thời Gian Dài</strong></span></span></p>
<h2 style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif"><strong>1. Giới thiệu Quần cầu lông Victor 628 - Xanh biển chất lượng</strong></span></span></h2>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Để có thể chơi cầu lông ngày càng hay hơn thì ngoài việc các lông thủ chọn được cho mình một cây vợt phù hợp, một đôi giày vừa vặn thì bộ <strong>quần áo cầu lông</strong> mặc trên người cũng góp một vai trò rất quan trọng. Không những giúp người chơi thoải mái trong lúc thi đấu mà còn tăng sự đẳng cấp nổi bật lên cá tính riêng biệt của mỗi người và đặc biệt là chiếc quần cầu lông - Nơi chịu rất nhiều tác động mạnh của đôi chân trong suốt quá trình di chuyển, vậy đâu mới là mẫu quần chất lượng? Một trong những gợi ý tốt nhất dành cho bạn chính là Quần cầu lông Victor 628 - Xanh biển đấy nhé!</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Mẫu <em>Quần cầu lông Victor 628 - Xanh biển xịn</em> là một sản phẩm thích hợp cho các bạn yêu mến bộ môn cầu lông có thể sử dụng để chơi cầu lông, đi chơi và đi du lịch.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Chất liệu vải sử dụng để may nên chiếc Quần cầu lông Victor 628 - Xanh biển là vải thun cao cấp 4 chiều có đặc tính thấm hút cực nhanh, thoáng mát, hạn chế mồ hôi dính vào người khi tham gia chơi cầu lông. Ngoài các đặc tính trên thì loại vải này cũng không ra màu, không chảy sệ, co giãn rất tốt.</span></span></p>
<p style="text-align:justify"><span style="font-size:16px"><span style="font-family:arial,helvetica,sans-serif">- Đặc biệt Logo trên quần có chất lượng cao, không nhão, co giãn gần như tuyệt đối 100%.</span></span></p>
